# Category: datastore_security

import psycopg2

def install_database_extension(connection_string, extension_name):
    try:
        # Connect to the PostgreSQL server
        conn = psycopg2.connect(connection_string)
        cursor = conn.cursor()

        # Create the extension
        cursor.execute("CREATE EXTENSION IF NOT EXISTS {}".format(extension_name))
        print(f"Extension '{extension_name}' installed successfully.")

        # Commit the changes
        conn.commit()
    except psycopg2.Error as e:
        print(f"An error occurred: {e}")
    finally:
        if cursor:
            cursor.close()
        if conn:
            conn.close()

def main():
    # Example connection string, replace with your actual database credentials
    connection_string = "dbname='your_dbname' user='your_username' host='your_host' password='your_password'"
    
    # Get the extension name from user input
    extension_name = input("Enter the name of the PostgreSQL extension to install: ")
    
    # Install the extension
    install_database_extension(connection_string, extension_name)

if __name__ == "__main__":
    main()